/**
 * calcMeta.ts - Centralized SEO metadata generator
 *
 * Single source of truth for every calculator page's SEO metadata.
 * Any route added to siteRoutes.ts automatically gets compliant metadata here.
 *
 * Usage in a page:
 *   import { getMeta } from "@/data/calcMeta";
 *   const meta = getMeta("/bmi-calculator");  // { title, description, h1, keywords, category }
 *
 * Or simply pass the path to SEOHead:
 *   <SEOHead path="/bmi-calculator" />
 */

import { calculatorRoutes, SITE_URL } from "./siteRoutes";

export interface CalcMeta {
  title: string;       // base title - chars - SEOHead appends "- CalcHive" - total -
  description: string; // 140-160 chars, keyword-rich
  h1: string;          // keyword-rich H1 (for reference; pages render their own H1)
  keywords: string;    // comma-separated keyword list
  category: string;    // from siteRoutes
  canonical: string;   // full canonical URL
}

// -R- Word capitalisation map -R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R
const WORD_MAP: Record<string, string> = {
  bmi: "BMI", bmr: "BMR", gpa: "GPA", gdp: "GDP",
  btu: "BTU", ctr: "CTR", cpm: "CPM", roi: "ROI",
  ip: "IP", url: "URL", hp: "HP", mpg: "MPG",
  youtube: "YouTube", tiktok: "TikTok",
  pinterest: "Pinterest", instagram: "Instagram",
  fiverr: "Fiverr", upwork: "Upwork", shopify: "Shopify",
  x: "X", base64: "Base64",
};

// -R- Acronym full expansions (for descriptive titles) -R-R-R-R-R-R-R-R-R-R-R-R
const ACRONYM_EXPAND: Record<string, string> = {
  BMI: "Body Mass Index",
  BMR: "Basal Metabolic Rate",
  GPA: "Grade Point Average",
  GDP: "Gross Domestic Product",
  BTU: "British Thermal Unit",
  CTR: "Click-Through Rate",
  CPM: "Cost Per Mille",
  HP:  "Horsepower",
};

/** Convert `/bmi-calculator` - "BMI Calculator" */
function slugToLabel(path: string): string {
  return path
    .replace(/^\//, "")
    .split("-")
    .map((w) => WORD_MAP[w.toLowerCase()] ?? w.charAt(0).toUpperCase() + w.slice(1))
    .join(" ");
}

/** Strip generic suffix to get the core concept */
function toShortLabel(label: string): string {
  return label
    .replace(/ Calculator$/, "")
    .replace(/ Tool$/, "")
    .replace(/ Generator$/, "")
    .replace(/ Converter$/, "")
    .replace(/ Estimator$/, "")
    .replace(/ Predictor$/, "")
    .replace(/ Roller$/, "")
    .replace(/ Counter$/, "")
    .replace(/ Decoder$/, "")
    .trim();
}

// -R- Title builder -R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R
// SEOHead appends " - CalcHive" (11 chars). Aim for base - chars (total -
// Format: "[Label] - Free Online [Expansion]" or "Free Online [Label]" fallback.
function buildTitle(label: string, shortLabel: string): string {
  // Use acronym expansion for richer title when available (BMI - Body Mass Index)
  const expanded = ACRONYM_EXPAND[shortLabel.toUpperCase()] ?? shortLabel;

  // v1: "[Label] - Free Online [Expanded]"
  const v1 = `${label} - Free Online ${expanded}`;
  if (v1.length <= 54) return v1;

  // v2: "[Label] - Free Online [ShortLabel]" (non-expanded)
  const v2 = `${label} - Free Online ${shortLabel}`;
  if (v2.length <= 54) return v2;

  // v3: "Free Online [Label]"
  const v3 = `Free Online ${label}`;
  if (v3.length <= 54) return v3;

  // v4: label alone (long names like "Social Media Manager Pricing Calculator")
  return label.length <= 54 ? label : label.slice(0, 51) + "...";
}

// -R- Description builder -R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-
// Target: 140-160 chars. Category-specific templates for higher keyword density.
function buildDescription(label: string, shortLabel: string, category: string): string {
  const s = shortLabel.toLowerCase();
  const longLabel = label.length > 22;

  let raw: string;

  switch (category) {
    case "Financial":
      raw = longLabel
        ? `Use our free ${label} for instant, accurate financial results. No signup required - fast, mobile-friendly, and 100% free.`
        : `Use our free online ${label} for instant, accurate results. No signup required - calculate ${s} payments, interest, and loan costs in seconds. Mobile-friendly.`;
      break;

    case "Health":
      raw = longLabel
        ? `Use our free online ${label} for instant, accurate health results. No signup or download needed - fast, private, and mobile-friendly.`
        : `Calculate your ${s} instantly with our free online ${label}. Accurate health metrics in seconds - no signup needed, private, and mobile-friendly.`;
      break;

    case "Math":
      raw = longLabel
        ? `Use our free online ${label} for instant, step-by-step results. No signup or download needed - fast, accurate, and 100% free.`
        : `Calculate ${s} instantly with our free online ${label}. Step-by-step results - no signup needed, fast, accurate, and 100% free.`;
      break;

    case "Freelance":
      raw = `Calculate your ${s} with our free online ${label}. Instant results for freelancers - no signup, no download, mobile-friendly and 100% free.`;
      break;

    case "YouTube":
      raw = longLabel
        ? `Use our free ${label} for instant YouTube earnings estimates. No signup needed - fast, accurate, and built for YouTube creators.`
        : `Estimate your ${s} with our free online ${label}. Instant results for YouTube creators - no signup, mobile-friendly and 100% free.`;
      break;

    case "Social":
      raw = longLabel
        ? `Use our free ${label} for instant social media estimates. No signup required - fast, accurate, and built for creators and marketers.`
        : `Calculate your ${s} with our free online ${label}. Instant results for social media creators - no signup, mobile-friendly and 100% free.`;
      break;

    case "Dropshipping":
      raw = `Calculate ${s} instantly with our free online ${label}. Essential for dropshippers - see profit margins, break-even points, and costs instantly. No signup needed.`;
      break;

    case "Income":
      raw = `Calculate your ${s} with our free online ${label}. Instant income estimates - no signup or download needed, fast, mobile-friendly and 100% free.`;
      break;

    case "Housing":
      raw = `Use our free online ${label} for instant, accurate home improvement results. No signup or download needed - fast, mobile-friendly, and 100% free.`;
      break;

    case "Transportation":
      raw = longLabel
        ? `Use our free ${label} for instant vehicle and travel estimates. No signup needed - fast, accurate, mobile-friendly and 100% free.`
        : `Calculate ${s} instantly with our free online ${label}. Instant vehicle estimates - no signup needed, fast, mobile-friendly and 100% free.`;
      break;

    case "Electronics":
      raw = `Use our free online ${label} for instant, accurate electrical calculations. No signup or download needed - fast, mobile-friendly, and 100% free.`;
      break;

    case "Weather":
      raw = `Calculate ${s} instantly with our free online ${label}. Accurate weather and temperature results - no signup needed, fast, mobile-friendly and 100% free.`;
      break;

    case "Measurement":
      raw = longLabel
        ? `Use our free ${label} for instant measurement and conversion results. No signup needed - fast, accurate, mobile-friendly and 100% free.`
        : `Calculate ${s} instantly with our free online ${label}. Accurate measurement results - no signup needed, fast, mobile-friendly and 100% free.`;
      break;

    default:
      raw = longLabel
        ? `Use our free ${label} for instant, accurate results. No signup or download required - fast, mobile-friendly, and 100% free.`
        : `Calculate ${s} instantly with our free online ${label}. No signup or download needed - fast, accurate, mobile-friendly, and 100% free.`;
  }

  return raw.length <= 160 ? raw : raw.slice(0, 157) + "...";
}

// -R- Keywords builder -R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-
// Category-specific high-value keyword expansions beyond the generic six.
function buildKeywords(label: string, shortLabel: string, category: string): string {
  const l = label.toLowerCase();
  const s = shortLabel.toLowerCase();
  const cat = category.toLowerCase();

  const base = [
    l,
    `free ${l}`,
    `online ${l}`,
    `free online ${l}`,
    `${s} calculator`,
    `${cat} calculator`,
    "free calculator",
    "online calculator",
  ];

  const catExtra: Record<string, string[]> = {
    financial: [
      "loan calculator", "mortgage calculator", "interest rate calculator",
      "payment calculator", "finance calculator", "free finance tool",
      "amortization calculator", "investment calculator",
    ],
    health: [
      "bmi calculator", "calorie calculator", "health calculator",
      "free health tool", "body calculator", "fitness calculator",
      "weight calculator", "wellness calculator",
    ],
    math: [
      "free math calculator", "online math tool", "percentage calculator",
      "algebra calculator", "statistics calculator", "math solver",
    ],
    freelance: [
      "freelance calculator", "earnings calculator", "hourly rate calculator",
      "income calculator", "self-employed calculator", "freelance rate tool",
    ],
    youtube: [
      "youtube calculator", "creator earnings", "ad revenue calculator",
      "youtube money calculator", "youtube monetization tool",
    ],
    social: [
      "social media calculator", "engagement calculator",
      "influencer calculator", "creator tool", "social media tool",
    ],
    dropshipping: [
      "profit calculator", "dropshipping tool", "ecommerce calculator",
      "margin calculator", "dropship profit tool", "product cost calculator",
    ],
    income: [
      "income calculator", "passive income calculator",
      "side hustle calculator", "earnings estimator", "revenue calculator",
    ],
    housing: [
      "home calculator", "construction calculator", "home improvement tool",
      "house calculator", "building calculator",
    ],
    transportation: [
      "vehicle calculator", "car calculator", "fuel calculator",
      "mileage calculator", "auto calculator",
    ],
    electronics: [
      "electronics calculator", "electrical calculator", "circuit calculator",
      "ohms law calculator", "voltage calculator",
    ],
    weather: [
      "weather calculator", "temperature calculator", "climate tool",
    ],
    measurement: [
      "unit converter", "measurement tool", "conversion calculator",
      "unit calculator", "metric converter",
    ],
    "date & time": [
      "date calculator", "time calculator", "date difference calculator",
      "days between dates", "calendar calculator",
    ],
    tools: [
      "free tool", "utility calculator", "online tool", "productivity calculator",
    ],
  };

  const extras = catExtra[cat] ?? [];
  return [...new Set([...base, ...extras])].join(", ");
}

// -R- Per-route metadata registry -R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-
const REGISTRY: Record<string, CalcMeta> = {};

for (const route of calculatorRoutes) {
  const label    = slugToLabel(route.path);
  const shortLbl = toShortLabel(label);
  REGISTRY[route.path] = {
    title:       buildTitle(label, shortLbl),
    description: buildDescription(label, shortLbl, route.category),
    h1:          buildTitle(label, shortLbl),
    keywords:    buildKeywords(label, shortLbl, route.category),
    category:    route.category,
    canonical:   `${SITE_URL}${route.path}`,
  };
}

// -R- Public API -R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-
/** Returns auto-generated SEO metadata for a calculator path, or undefined for unknown paths. */
export function getMeta(path: string): CalcMeta | undefined {
  return REGISTRY[path];
}

/** Returns the full metadata registry (all calculator paths). */
export function getAllMeta(): Record<string, CalcMeta> {
  return { ...REGISTRY };
}


