import { Helmet } from "react-helmet-async";
import { getMeta } from "@/data/calcMeta";
import { useEffect } from "react";
import { calculatorRoutes, SITE_URL } from "@/data/siteRoutes";

// -R- Types -R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R

export interface HowToStep {
  name: string;
  text: string;
}

interface SEOHeadProps {
  // Auto-mode: just pass path="/bmi-calculator" - all metadata resolved from calcMeta.ts
  path?: string;
  // Manual-override mode: pass explicit values (used by Home, About, Contact, etc.)
  title?: string;
  description?: string;
  canonical?: string;
  keywords?: string;
  category?: string;
  breadcrumbName?: string;
  schemaType?: "SoftwareApplication" | "WebApplication";
  schemaApplicationCategory?: string;
  // FAQPage schema - enables rich FAQ results in Google (accordion snippets)
  faqs?: Array<{ q: string; a: string }>;
  // HowTo schema - enables step-by-step rich results in Google
  howToSteps?: HowToStep[];
}

// -R- Helpers -R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R

/** Use a static social image so Netlify/Vercel/Cloudflare static deploys do not
 *  depend on a missing dynamic /api/og endpoint. */
function buildOgImageUrl(title?: string, category?: string): string {
  void title;
  void category;
  return `${SITE_URL}/opengraph.webp`;
}

function normalizeCanonicalUrl(value: string): string {
  const raw = (value || "/").trim() || "/";
  const url = raw.startsWith("http")
    ? new URL(raw)
    : new URL(raw.startsWith("/") ? raw : `/${raw}`, `${SITE_URL}/`);
  const normalizedPath = url.pathname === "/"
    ? "/"
    : url.pathname.replace(/\/+$/, "");
  return normalizedPath === "/" ? `${SITE_URL}/` : `${SITE_URL}${normalizedPath}`;
}

/** ISO 8601 date string for lastmod / dateModified */
const BUILD_DATE = new Date().toISOString().split("T")[0];

/**
 * Map a route category - schema.org applicationCategory.
 * https://schema.org/applicationCategory
 */
function resolveAppCategory(category?: string): string {
  if (!category) return "UtilitiesApplication";
  const c = category.toLowerCase();
  if (
    c.includes("financ") || c.includes("loan") || c.includes("tax") ||
    c.includes("invest") || c.includes("income") || c.includes("salary") ||
    c.includes("freelan") || c.includes("dropship") || c.includes("youtube") ||
    c.includes("tiktok") || c.includes("social")
  ) return "FinanceApplication";
  if (
    c.includes("health") || c.includes("bmi") || c.includes("calorie") ||
    c.includes("fitness") || c.includes("pregnan")
  ) return "HealthApplication";
  if (c.includes("math") || c.includes("science")) return "EducationalApplication";
  return "UtilitiesApplication";
}

/**
 * Auto-generate sensible HowTo steps when none are provided explicitly.
 * These are generic but still valid schema.org/HowTo entries.
 */
function autoHowToSteps(label: string, category: string): HowToStep[] {
  const c = category.toLowerCase();

  if (c.includes("financ") || c.includes("loan") || c.includes("mortgage") ||
      c.includes("invest") || c.includes("tax") || c.includes("salary") ||
      c.includes("income") || c.includes("freelan") || c.includes("dropship")) {
    return [
      { name: "Enter your financial values", text: `Open the ${label} and enter your primary financial figures such as amount, rate, or income.` },
      { name: "Adjust optional settings", text: "Set any additional parameters like term length, tax rates, fees, or time period to refine your calculation." },
      { name: "Read your instant result", text: "The calculator displays your result in real time - no submit button needed. Results update as you type or adjust sliders." },
    ];
  }
  if (c.includes("health") || c.includes("bmi") || c.includes("calorie") ||
      c.includes("pregnan") || c.includes("fitness")) {
    return [
      { name: "Enter your personal details", text: `Open the ${label} and enter your relevant measurements such as height, weight, or age.` },
      { name: "Select your preferred units", text: "Choose between imperial (lbs, ft/in) or metric (kg, cm) units depending on your preference." },
      { name: "View your health result", text: "Your result is calculated instantly and displayed alongside reference ranges to help you interpret it." },
    ];
  }
  if (c.includes("youtube") || c.includes("social") || c.includes("tiktok") ||
      c.includes("instagram") || c.includes("creator")) {
    return [
      { name: "Enter your channel or account metrics", text: `Open the ${label} and input your views, subscribers, engagement rate, or follower count.` },
      { name: "Adjust revenue or engagement settings", text: "Set CPM rates, niche multipliers, or sponsorship values relevant to your content type." },
      { name: "See your estimated earnings or metrics", text: "Get an instant breakdown of estimated revenue, engagement metrics, or growth projections." },
    ];
  }
  if (c.includes("housing") || c.includes("construction") || c.includes("concrete") ||
      c.includes("roof") || c.includes("tile") || c.includes("gravel")) {
    return [
      { name: "Enter your project dimensions", text: `Open the ${label} and input the relevant measurements such as area, length, width, or depth.` },
      { name: "Select material type or density", text: "Choose the material or density setting that matches your project requirements." },
      { name: "Get your quantity estimate", text: "The calculator instantly shows the quantity of material needed, with recommended overage to account for waste." },
    ];
  }

  // Generic fallback
  return [
    { name: `Open the ${label}`, text: `Navigate to the ${label} on CalcHive - no login or download required.` },
    { name: "Enter your values", text: "Fill in the required fields or move the sliders to your desired values. All inputs update the result in real time." },
    { name: "Read and share your result", text: "Your answer appears instantly below the inputs. Results are calculated client-side for complete privacy." },
  ];
}

// -R- Component -R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R

export default function SEOHead({
  path,
  title: titleProp,
  description: descProp,
  canonical: canonicalProp,
  keywords: keywordsProp,
  category: categoryProp,
  breadcrumbName,
  schemaType = "SoftwareApplication",
  schemaApplicationCategory,
  faqs,
  howToSteps,
}: SEOHeadProps) {
  const auto = path ? getMeta(path) : undefined;

  const baseTitle   = titleProp     ?? auto?.title       ?? "CalcHive";
  const description = descProp      ?? auto?.description ?? "";
  const canonical   = canonicalProp ?? path              ?? "/";
  const keywords    = keywordsProp  ?? auto?.keywords    ?? "";
  const category    = categoryProp  ?? auto?.category    ?? "";

  const fullTitle         = /calchive/i.test(baseTitle) ? baseTitle : `${baseTitle} - CalcHive`;
  const absoluteCanonical = normalizeCanonicalUrl(canonical);
  const appCategory       = schemaApplicationCategory ?? resolveAppCategory(category);
  const breadcrumbLabel   = breadcrumbName ?? baseTitle;
  const isHomepage        = absoluteCanonical === `${SITE_URL}/`;
  const isCalculator      = !isHomepage && category !== "company" && category !== "home";

  useEffect(() => {
    const ensureHeadTag = <T extends HTMLElement>(id: string, create: () => T): T => {
      const existing = document.getElementById(id) as T | null;
      if (existing) return existing;
      const created = create();
      created.id = id;
      document.head.appendChild(created);
      return created;
    };

    const canonicalTag = ensureHeadTag("calchive-canonical", () => {
      const link = document.createElement("link");
      link.rel = "canonical";
      return link;
    });
    canonicalTag.setAttribute("href", absoluteCanonical);

    const ogUrlTag = ensureHeadTag("calchive-og-url", () => {
      const meta = document.createElement("meta");
      meta.setAttribute("property", "og:url");
      return meta;
    });
    ogUrlTag.setAttribute("content", absoluteCanonical);

    document.title = fullTitle;
    document.querySelectorAll('meta[name="description"]').forEach((meta) => {
      meta.setAttribute("content", description);
    });
    document.querySelectorAll('meta[property="og:title"]').forEach((meta) => {
      meta.setAttribute("content", fullTitle);
    });
    document.querySelectorAll('meta[property="og:description"]').forEach((meta) => {
      meta.setAttribute("content", description);
    });
    document.querySelectorAll('meta[property="og:url"]').forEach((meta) => {
      meta.setAttribute("content", absoluteCanonical);
    });
    document.querySelectorAll('meta[name="twitter:title"]').forEach((meta) => {
      meta.setAttribute("content", fullTitle);
    });
    document.querySelectorAll('meta[name="twitter:description"]').forEach((meta) => {
      meta.setAttribute("content", description);
    });
  }, [absoluteCanonical, description, fullTitle]);

  // -R BreadcrumbList -R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R
  const breadcrumbItems: Array<{
    "@type": string; position: number; name: string; item?: string
  }> = [
    { "@type": "ListItem", position: 1, name: "Home", item: `${SITE_URL}/` },
  ];
  if (category && category !== "home" && category !== "company") {
    breadcrumbItems.push({
      "@type": "ListItem",
      position: 2,
      name: category,
      item: `${SITE_URL}/?cat=${encodeURIComponent(category).replace(/%20/g, "+")}`,
    });
    breadcrumbItems.push({ "@type": "ListItem", position: 3, name: breadcrumbLabel });
  } else if (!isHomepage) {
    breadcrumbItems.push({ "@type": "ListItem", position: 2, name: breadcrumbLabel });
  }

  const breadcrumbSchema = {
    "@context": "https://schema.org",
    "@type": "BreadcrumbList",
    "itemListElement": breadcrumbItems,
  };

  // -R WebPage -R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-
  const webPageSchema = {
    "@context": "https://schema.org",
    "@type": "WebPage",
    "name": fullTitle,
    "description": description,
    "url": absoluteCanonical,
    "datePublished": "2024-01-01",
    "dateModified": BUILD_DATE,
    "inLanguage": "en-US",
    "isPartOf": {
      "@type": "WebSite",
      "name": "CalcHive",
      "url": `${SITE_URL}/`,
    },
    "breadcrumb": breadcrumbSchema,
    "speakable": {
      "@type": "SpeakableSpecification",
      "cssSelector": ["h1", "[data-speakable]"],
    },
  };

  // -R SoftwareApplication (calculator pages only) -R-R-R-R-R-R-R-R-R-R-R-R-R-R
  // No aggregateRating - only add real ratings if you collect them from users.
  const appSchema = isCalculator ? {
    "@context": "https://schema.org",
    "@type": "WebApplication",
    "name": fullTitle,
    "description": description,
    "url": absoluteCanonical,
    "applicationCategory": "UtilitiesApplication",
    "operatingSystem": "Web Browser",
    "browserRequirements": "Requires JavaScript. Works in all modern browsers.",
    "isFamilyFriendly": true,
    "featureList": [
      "Instant real-time results",
      "No account or signup required",
      "100% free to use",
      "Mobile friendly",
      "Privacy-first - all calculations run client-side",
    ],
    "offers": {
      "@type": "Offer",
      "price": "0",
      "priceCurrency": "USD",
    },
    "provider": {
      "@type": "Organization",
      "name": "CalcHive",
      "url": `${SITE_URL}/`,
    },
  } : null;

  // -R HowTo (calculator pages only) -R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R
  // Auto-generates steps when not provided explicitly.
  const steps = howToSteps ?? (isCalculator ? autoHowToSteps(baseTitle, category) : null);
  const howToSchema = steps && steps.length > 0 ? {
    "@context": "https://schema.org",
    "@type": "HowTo",
    "name": `How to use the ${baseTitle}`,
    "description": `Step-by-step guide to using the free online ${baseTitle} on CalcHive.`,
    "totalTime": "PT1M",
    "tool": [{
      "@type": "HowToTool",
      "name": "CalcHive Calculator",
    }],
    "step": steps.map((s, i) => ({
      "@type": "HowToStep",
      "position": i + 1,
      "name": s.name,
      "text": s.text,
      "url": `${absoluteCanonical}#step-${i + 1}`,
    })),
  } : null;

  // -R FAQPage -R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-
  const faqSchema = faqs && faqs.length > 0 ? {
    "@context": "https://schema.org",
    "@type": "FAQPage",
    "mainEntity": faqs.map(({ q, a }) => ({
      "@type": "Question",
      "name": q,
      "acceptedAnswer": { "@type": "Answer", "text": a },
    })),
  } : null;

  // -R WebSite + Organization (homepage only) -R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R
  const websiteSchema = isHomepage ? {
    "@context": "https://schema.org",
    "@type": "WebSite",
    "name": "CalcHive",
    "alternateName": "CalcHive Free Online Calculators",
    "url": `${SITE_URL}/`,
    "description": `CalcHive offers ${calculatorRoutes.length}+ free online calculators for finance, health, math, freelancing, YouTube and more. Fast, accurate and easy to use. No signup required.`,
    "inLanguage": "en-US",
      "potentialAction": {
      "@type": "SearchAction",
      "target": {
        "@type": "EntryPoint",
        "urlTemplate": `${SITE_URL}/search?q={search_term_string}`,
      },
      "query-input": "required name=search_term_string",
    },
  } : null;

  const organizationSchema = isHomepage ? {
    "@context": "https://schema.org",
    "@type": "Organization",
    "name": "CalcHive",
    "url": `${SITE_URL}/`,
    "logo": {
      "@type": "ImageObject",
        "url": `${SITE_URL}/logo-192.png`,
      "width": 192,
      "height": 192,
    },
    "description": `CalcHive offers ${calculatorRoutes.length}+ free online calculators for finance, health, math, freelancing, YouTube and more. Fast, accurate and easy to use. No signup required.`,
    "foundingDate": "2024",
    "sameAs": [],
  } : null;

  // -R ItemList (homepage only) - catalogue of all calculators -R-R-R-R-R-R-R-R
  const itemListSchema = isHomepage ? {
    "@context": "https://schema.org",
    "@type": "ItemList",
    "name": "Free Online Calculators - CalcHive",
    "description": `A collection of ${calculatorRoutes.length}+ free online calculators covering finance, health, math, freelancers, and creators.`,
    "numberOfItems": calculatorRoutes.length,
    "itemListElement": calculatorRoutes.slice(0, 50).map((r, i) => ({
      "@type": "ListItem",
      "position": i + 1,
      "url": `${SITE_URL}${r.path}`,
    })),
  } : null;

  return (
    <Helmet>
      <title>{fullTitle}</title>
      <meta name="description" content={description} />
      <meta name="robots" content="index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1" />
      {keywords && <meta name="keywords" content={keywords} />}

      {/* Open Graph */}
      <meta property="og:title" content={fullTitle} />
      <meta property="og:description" content={description} />
      <meta property="og:type" content="website" />
      <meta property="og:site_name" content="CalcHive" />
      <meta property="og:locale" content="en_US" />
      <meta property="og:image" content={buildOgImageUrl(baseTitle, category)} />
      <meta property="og:image:width" content="1200" />
      <meta property="og:image:height" content="630" />
      <meta property="og:image:alt" content={fullTitle} />

      {/* Twitter / X */}
      <meta name="twitter:card" content="summary_large_image" />
      <meta name="twitter:site" content="@calchive" />
      <meta name="twitter:creator" content="@calchive" />
      <meta name="twitter:title" content={fullTitle} />
      <meta name="twitter:description" content={description} />
      <meta name="twitter:image" content={buildOgImageUrl(baseTitle, category)} />
      <meta name="twitter:image:alt" content={fullTitle} />

      {/* Mobile */}
      <meta name="theme-color" content="#7c3aed" />
      <meta name="mobile-web-app-capable" content="yes" />
      <meta name="apple-mobile-web-app-capable" content="yes" />

      {/* -R JSON-LD Structured Data -R */}

      {/* BreadcrumbList - breadcrumb trail in search results */}
      <script type="application/ld+json">{JSON.stringify(breadcrumbSchema)}</script>

      {/* WebPage - base page entity with dates and speakable */}
      <script type="application/ld+json">{JSON.stringify(webPageSchema)}</script>

      {/* SoftwareApplication - calculator tool card (no fake ratings) */}
      {appSchema && (
        <script type="application/ld+json">{JSON.stringify(appSchema)}</script>
      )}

      {/* HowTo - step-by-step rich result in Google (auto-generated or explicit) */}
      {howToSchema && (
        <script type="application/ld+json">{JSON.stringify(howToSchema)}</script>
      )}

      {/* FAQPage - FAQ accordion rich results in Google */}
      {faqSchema && (
        <script type="application/ld+json">{JSON.stringify(faqSchema)}</script>
      )}

      {/* WebSite - enables Sitelinks Search Box in Google (homepage only) */}
      {websiteSchema && (
        <script type="application/ld+json">{JSON.stringify(websiteSchema)}</script>
      )}

      {/* Organization - brand knowledge panel (homepage only) */}
      {organizationSchema && (
        <script type="application/ld+json">{JSON.stringify(organizationSchema)}</script>
      )}

      {/* ItemList - calculator catalogue for rich list results (homepage only) */}
      {itemListSchema && (
        <script type="application/ld+json">{JSON.stringify(itemListSchema)}</script>
      )}
    </Helmet>
  );
}




